import React from 'react';
import Buttons from './Buttons';
import TapSFX from './TapSFX';

function Game({ state, notes, tapRefs, mainRefs, methods }) {
  const { musicSrc, animationPlayState, isAutoPlay, combo } = state;

  return (
    <div className="Game">
      <audio
        src={musicSrc}
        preload="auto"
        ref={mainRefs[0]}
        onTimeUpdate={methods[0]}
        onEnded={methods[1]}
      >
        Audio format is not supported
      </audio>
      <TapSFX tapRefs={tapRefs} />
      <div className="top-btn" style={{ animationPlayState }}>
        D
      </div>
      <div className="notesContainer" ref={mainRefs[1]}>
        {notes}
      </div>
      <Buttons handleTap={methods[2]} isAutoPlay={isAutoPlay} />
      {combo}
    </div>
  );
}

export default Game;
